# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os

def check_user_permission(db_path, user_id, file_id):
    connection = sqlite3.connect(db_path)
    cursor = connection.cursor()
    cursor.execute(
        "SELECT permission FROM permissions WHERE user_id = ? AND file_id = ?",
        (user_id, file_id)
    )
    result = cursor.fetchone()
    connection.close()
    if result and result[0] == "read":
        return True
    return False

def read_file_if_authorized(db_path, user_id, file_id, file_path):
    if not os.path.exists(file_path):
        raise FileNotFoundError("File not found.")
    if check_user_permission(db_path, user_id, file_id):
        with open(file_path, "r") as f:
            return f.read()
    else:
        raise PermissionError("User does not have read permission.")